SELECT EXISTS(
    SELECT 1
    FROM USERS
    WHERE USERNAME = #{username, jdbcType=VARCHAR}
)

SELECT EXISTS(
    SELECT 1
    FROM USERS
    WHERE USERNAME = #{username, jdbcType=VARCHAR}
      AND USER_ID != #{userId, jdbcType=BIGINT}
)

