UPDATE USERS SET USERNAME = #{username, jdbcType=VARCHAR}, USER_NAME = #{displayName, jdbcType=VARCHAR}, DEPARTMENT = #{department, jdbcType=VARCHAR}, TEAM = #{team, jdbcType=VARCHAR}, POSITION = #{position, jdbcType=VARCHAR},
